import{_ as t,o as a,c as o,ae as r}from"./chunks/framework.BD9pLfSD.js";const u=JSON.parse('{"title":"Track A: Agent Core & Payment Strategies","description":"","frontmatter":{},"headers":[],"relativePath":"docs/plans/tracks/track_a_agent_core.md","filePath":"docs/plans/tracks/track_a_agent_core.md"}'),n={name:"docs/plans/tracks/track_a_agent_core.md"};function i(s,e,c,l,d,g){return a(),o("div",null,[...e[0]||(e[0]=[r('<h1 id="track-a-agent-core-payment-strategies" tabindex="-1">Track A: Agent Core &amp; Payment Strategies <a class="header-anchor" href="#track-a-agent-core-payment-strategies" aria-label="Permalink to &quot;Track A: Agent Core &amp; Payment Strategies&quot;">​</a></h1><p><strong>Branch Name:</strong> <code>feat/agent-payments-core</code><strong>Base Branch:</strong> <code>base-integration</code> (Consolidated)</p><h2 id="_1-objective" tabindex="-1">1. Objective <a class="header-anchor" href="#_1-objective" aria-label="Permalink to &quot;1. Objective&quot;">​</a></h2><p>To implement the &quot;Autonomous CFO&quot; logic within the SDK, transforming the Agent from a simple spender into a <strong>Liquidity Manager</strong> that bridges the corporate fiat world (Starpay) with the private crypto economy (ShadowWire/PrivacyCash).</p><p><strong>Key Concept:</strong> The Agent synchronizes treasury from Starpay (The Corporate Source) to <code>xb77_core</code> (The On-Chain Balance), enabling seamless operation.</p><h2 id="_2-core-components" tabindex="-1">2. Core Components <a class="header-anchor" href="#_2-core-components" aria-label="Permalink to &quot;2. Core Components&quot;">​</a></h2><h3 id="_2-1-the-liquidity-manager-new" tabindex="-1">2.1. The Liquidity Manager (New!) <a class="header-anchor" href="#_2-1-the-liquidity-manager-new" aria-label="Permalink to &quot;2.1. The Liquidity Manager (New!)&quot;">​</a></h3><p>The bridge between Fiat Treasury and Crypto Execution.</p><ul><li><strong>Path:</strong> <code>sdk/src/economy/liquidity_manager.ts</code></li><li><strong>Logic:</strong><ol><li><strong>Poll Starpay:</strong> Check corporate card limits/balance allocated by the human operator.</li><li><strong>Poll On-Chain:</strong> Check <code>xb77_core</code> program state for current operational capital.</li><li><strong>Rebalance:</strong> If On-Chain funds are low but Starpay has credit, initiate a Top-Up (mocked swap or bridge flow) to move value into the Private System.</li></ol></li></ul><h3 id="_2-2-the-payment-routing-engine-brain" tabindex="-1">2.2. The Payment Routing Engine (Brain) <a class="header-anchor" href="#_2-2-the-payment-routing-engine-brain" aria-label="Permalink to &quot;2.2. The Payment Routing Engine (Brain)&quot;">​</a></h3><ul><li><strong>Path:</strong> <code>sdk/src/economy/payment_router.ts</code></li><li><strong>Safety Layer (Range):</strong> Before any move, consult Range API. <em>&quot;Is this destination safe?&quot;</em></li><li><strong>Routing Logic:</strong><ul><li><strong>Internal:</strong> Use <strong>Privacy Cash</strong> (Light) or <strong>ShadowWire</strong> for Agent-to-Agent payments.</li><li><strong>External:</strong> Use <strong>Starpay</strong> Virtual Card for Web2 payments.</li><li><strong>Escape:</strong> Use <strong>SilentSwap</strong> to exit to other chains if Solana is congested or compromised.</li></ul></li></ul><h3 id="_2-3-adapters-toolkit" tabindex="-1">2.3. Adapters (Toolkit) <a class="header-anchor" href="#_2-3-adapters-toolkit" aria-label="Permalink to &quot;2.3. Adapters (Toolkit)&quot;">​</a></h3><ul><li><strong>StarpayAdapter:</strong> Read-Write. Reads balance (Funding) AND Issues cards (Spending).</li><li><strong>PrivacyCashAdapter:</strong> Interface to <code>privacy-cash-sdk</code>.</li><li><strong>ShadowWireAdapter:</strong> Interface to ShadowWire SDK.</li><li><strong>RangeAdapter:</strong> Interface to Range Compliance API.</li></ul><h3 id="_2-4-mcp-integration-active-tools" tabindex="-1">2.4. MCP Integration (Active Tools) <a class="header-anchor" href="#_2-4-mcp-integration-active-tools" aria-label="Permalink to &quot;2.4. MCP Integration (Active Tools)&quot;">​</a></h3><ul><li><code>cfo_check_treasury</code>: Returns combined balance (Fiat + Crypto).</li><li><code>cfo_rebalance</code>: Moves funds from Starpay -&gt; Crypto.</li><li><code>cfo_pay</code>: Smart routing based on intent.</li></ul><h2 id="_3-integration-with-existing-programs" tabindex="-1">3. Integration with Existing Programs <a class="header-anchor" href="#_3-integration-with-existing-programs" aria-label="Permalink to &quot;3. Integration with Existing Programs&quot;">​</a></h2><h3 id="link-to-xb77-core" tabindex="-1">Link to <code>xb77_core</code> <a class="header-anchor" href="#link-to-xb77-core" aria-label="Permalink to &quot;Link to `xb77_core`&quot;">​</a></h3><ul><li>This track&#39;s SDK interacts directly with the <code>xb77_core</code> program.</li><li>When rebalancing, the SDK calls an instruction on <code>xb77_core</code> (e.g., <code>deposit_liquidity</code>) to reflect the new funds available for the agent&#39;s logic.</li></ul><h3 id="link-to-xb77-gateway" tabindex="-1">Link to <code>xb77_gateway</code> <a class="header-anchor" href="#link-to-xb77-gateway" aria-label="Permalink to &quot;Link to `xb77_gateway`&quot;">​</a></h3><ul><li>The Agent uses its <strong>Noir Proof</strong> (<code>agent_badge</code>) to authenticate against the Starpay Adapter (simulated auth) and the <code>xb77_core</code> program, proving it is the authorized entity to manage these funds.</li></ul><h2 id="_4-execution-plan" tabindex="-1">4. Execution Plan <a class="header-anchor" href="#_4-execution-plan" aria-label="Permalink to &quot;4. Execution Plan&quot;">​</a></h2><ol><li><strong>Interfaces:</strong> Define <code>LiquiditySource</code> (Starpay) and <code>PrivacyRail</code> (ShadowWire/Light).</li><li><strong>Starpay Integration:</strong> Implement <code>StarpayAdapter</code> focusing on the &quot;Get Balance&quot; and &quot;Fund&quot; flows.</li><li><strong>Core Link:</strong> Update SDK to read/write to <code>xb77_core</code> state.</li><li><strong>Range Integration:</strong> Add the <code>validateAddress</code> check in the Router.</li><li><strong>MCP Tools:</strong> Expose <code>check_treasury</code> and <code>rebalance</code>.</li></ol>',22)])])}const p=t(n,[["render",i]]);export{u as __pageData,p as default};
